// PDU Model
package ade

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40020/idl"
)

// Interface for ADE chips directly connected to main controller
type Ade interface {
	idl.Object

	// Retrieve the ADE metadata.
	//
	//	@return ADE metadata
	GetMetaData(ctx context.Context) (MetaData, error)

	// Retrieve the latest raw samples.
	//
	//	@return Vector of samples, one for each channel
	GetLatestSample(ctx context.Context) ([]Sample, error)

	// Retrieve the values of all supported calibration registers.
	//
	//	@return Map of calibration register values
	GetCalibrationData(ctx context.Context) (RegisterMap, error)

	// Set new values for some or all calibration registers.
	//
	//	@note This command is only available during manufacturing!
	//
	//	@param regs  Map of new calibration register values
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//	@return 2 if the device is not in factory configuration mode
	SetCalibrationData(ctx context.Context, regs RegisterMap) (int32, error)
}

// ADE metadata
type MetaData struct {
	AdeType        string  // ADE chip model
	Channels       int32   // Number of channels
	CurrentDivider float64 // Divider for converting raw readings to Amperes
	VoltageDivider float64 // Divider for converting raw readings to Volts
	EnergyDivider  float64 // Divider for converting raw readings to Wh/VAh
}

// Raw sample data for a single channel
type Sample struct {
	Vrms int64 // RMS voltage
	Irms int64 // RMS current
	Watt int64 // Active power
	Va   int64 // Apparent power
	Wh   int64 // Active energy (for this sample)
	Vah  int64 // Apparent energy (for this sample)
}

// Map of ADE register values
type RegisterMap = map[string]int64
